/* ── Helpers ── */
const getSeries  = (iso3,key) => (DB[iso3]?.s?.[key]||[]).map(([year,value])=>({year,value}));
const getLatest  = (iso3,key) => { const s=getSeries(iso3,key); return s.length?s[s.length-1]:null; };
const getInfo    = iso3 => ({flag:'🌍',region:'Other',...(COUNTRY_META[iso3]||{}),n:(DB[iso3]?.n||iso3)});
const fmt        = (v,d=2) => v==null?'—':(typeof v==='number'?v.toLocaleString(undefined,{maximumFractionDigits:d}):String(v));
const srcColor   = s => (SRC_COLORS[s]||{bg:'#546E7A'}).bg;
const srcBadge   = s => { const c=SRC_COLORS[s]||{bg:'#546E7A',label:s||'—'}; return `<span class="badge" style="background:${c.bg}20;color:${c.bg};border:1px solid ${c.bg}33">${c.label}</span>`; };
const allISO     = Object.keys(DB).filter(k=>COUNTRY_META[k]).sort((a,b)=>(DB[a]?.n||a).localeCompare(DB[b]?.n||b));

/* ── Global CSV data store (avoids JSON-in-onclick bugs) ── */
const _CSV = {};
function registerCSV(key, rows) { _CSV[key] = rows; }
function dlCSV(fn, key) {
  const rows = typeof key==='string' ? _CSV[key] : key;
  if(!rows||!rows.length) return;
  const keys = Object.keys(rows[0]);
  const csv  = [keys.join(','),...rows.map(r=>keys.map(k=>r[k]).join(','))].join('\n');
  const a    = document.createElement('a');
  a.href     = URL.createObjectURL(new Blob([csv],{type:'text/csv'}));
  a.download = fn; a.click();
  setTimeout(()=>URL.revokeObjectURL(a.href), 1000);
}
